import { join } from 'node:path';
import type { Hono } from 'hono';
import type { Manager } from '@packages/runtime';
import { logger } from '@packages/logger';
import { registerPlatformRoutes } from './admin/index.ts';
import { registerAppRoutes } from './application.ts';

function pathValidationMiddleware(app: Hono) {
  app.use('*', async (c, next) => {
    const path = c.req.path;

    const allowedPatterns = [
      /^\/$/,                          // root
      /^\/health$/,                    // health check
      /^\/admin$/,                     // admin page
      /^\/admin\/.*$/,                 // admin routes
      /^\/api\/platform\/.*$/,         // platform API
      /^\/apps\/[a-zA-Z0-9_-]+$/,     // /apps/:name
      /^\/apps\/[a-zA-Z0-9_-]+\/.*$/, // /apps/:name/*
    ];

    const isAllowed = allowedPatterns.some(pattern => pattern.test(path));

    if (!isAllowed) {
      logger.warn('Invalid path access attempt', { path, method: c.req.method });
      try {
        const templatePath = join(Deno.cwd(), 'resources', 'templates', '404.html');
        const html = await Deno.readTextFile(templatePath);
        return new Response(html, {
          status: 404,
          headers: { 'Content-Type': 'text/html; charset=utf-8' },
        });
      } catch {
        return c.json({ error: 'Not Found' }, 404);
      }
    }

    return next();
  });
}

export function registerRoutes(app: Hono, manager: Manager): void {
  pathValidationMiddleware(app);
  registerPlatformRoutes(app, manager);

  registerAppRoutes(app, manager);
}

