import { type Context, Hono, type Next } from 'hono';
import { logger } from '@packages/logger';
import {
  AppErrorHandler,
  type AppInfo,
  AppModuleLoader,
  createRequestCtx,
  extractApi,
  extractIdentifier,
  extractStatic,
  getAppLogMeta,
  type Manager,
  type User,
} from '@packages/runtime';
import { getAppByName, installFromNPM } from '@packages/registry';
import { config } from '@packages/config';
import { migrate } from '@packages/schema';
import { join } from 'node:path';

type RequestCtx = Awaited<ReturnType<typeof createRequestCtx>>;

type AppBindings = {
  apiPath: string;
  requestCtx: RequestCtx;
  user?: User;
};

let managerInstance: Manager;
let appHttpHandler: {
  handleRequest: (c: Context, appInfo: AppInfo, apiPath: string) => Promise<Response>;
  clearCache: (appId?: string) => void;
};
const processedAppsCache = new Map<string, Hono<{ Bindings: AppBindings; Variables: AppBindings }>>();

const toError = (err: unknown): Error => (err instanceof Error ? err : new Error(String(err)));

async function exists(path: string) {
  try {
    await Deno.stat(path);
    return true;
  } catch {
    return false;
  }
}

async function parseBody(c: Context) {
  const contentType = c.req.header('Content-Type') || '';
  
  if (contentType.includes('application/json')) {
    return await c.req.json().catch(() => ({}));
  }
  
  if (contentType.includes('multipart/form-data') || contentType.includes('application/x-www-form-urlencoded')) {
    return await c.req.parseBody().catch(() => ({}));
  }
  
  if (contentType.includes('text/plain')) {
    return await c.req.text().catch(() => '');
  }

  return undefined;
}

async function getOrInstallApp(
  name: string,
  appsPath: string,
  tempPath: string,
  cachePath: string,
  c: Context,
): Promise<AppInfo | null> {
  const appDir = join(appsPath, name);
  const appDirExists = await exists(appDir);

  if (!appDirExists) {
    logger.debug(`App ${name} not found locally, attempting to install from NPM...`);
    try {
      const packageName = `@app/${name}`;
      const clearCache = managerInstance?.createClearCacheFunction();

      const installResult = await installFromNPM(
        packageName,
        'latest',
        appsPath,
        tempPath,
        cachePath,
        clearCache || (() => Promise.resolve()),
      );

      logger.info(`App ${name} installed successfully from NPM`);

      try {
        const url = new URL(c.req.url);
        const domain = `${url.protocol}//${url.host}`;
        const migrateResult = await migrate(installResult.appId, name, domain);
        if (migrateResult.success) {
          logger.info(`Migration successful for app ${name}`);
        } else {
          logger.warn(`Migration failed for app ${name}`);
        }
      } catch (_migrateError) {
        logger.warn(`Error during migration for app ${name}`);
      }
    } catch (_error) {
      logger.error(`Failed to install app from NPM: ${name}`);
      return null;
    }
  }

  let appInfo = await getAppByName(name, appsPath) as AppInfo | null;

  if (!appInfo) {
    logger.debug(`App ${name} not in registry, reading from filesystem...`);
    try {
      const appDir = join(appsPath, name);
      const stat = await Deno.stat(appDir);
      if (stat.isDirectory) {
        const manifestPath = join(appDir, 'manifest.json');
        try {
          const manifestText = await Deno.readTextFile(manifestPath);
          const manifest = JSON.parse(manifestText);

          if (manifest.id && manifest.name) {
            appInfo = {
              id: manifest.id,
              manifest,
              path: appDir,
            };
            await import('@packages/registry').then((m) => m.saveAppToRegistry(name, appInfo!));
            logger.debug(`App ${name} saved to registry`, { appId: appInfo!.id });
          }
        } catch {
          // No manifest.json
        }
      }
    } catch {
      // App directory doesn't exist
    }
  }

  if (appInfo) {
    logger.debug(`App ${name} loaded successfully`, {
      appId: appInfo.id,
      hasBackend: appInfo.manifest?.hasBackend,
      version: appInfo.manifest?.version,
    });
  }

  return appInfo;
}

function getAppHttpHandler() {
  if (!appHttpHandler) {
    logger.debug('Creating app HTTP handler...');
    const moduleLoader = new AppModuleLoader();
    const errorHandler = new AppErrorHandler();

    appHttpHandler = {
      handleRequest: async (c: Context, appInfo: AppInfo, apiPath: string): Promise<Response> => {
        const user = c.get('user') as User | undefined;
        const appId = appInfo.id;

        let subApp = processedAppsCache.get(appId);

        if (!subApp) {
          logger.info(`馃摜 Loading app for first time: ${appInfo.manifest?.name || appId}`);

          try {
            const { processedApp } = await moduleLoader.loadWithProcessedApp(appInfo, {
              appInfo,
              getUser: (ctx: any) => ctx.get('user'),
              getBody: async (ctx: any) => await parseBody(ctx),
              getQuery: (ctx: any) => ctx.req.query(),
              getParams: (ctx: any) => ctx.req.param(),
            });

            subApp = new Hono<{ Bindings: AppBindings; Variables: AppBindings }>();

            // Middleware to inject context from Env
            subApp.use('*', async (ctx, next) => {
              const env = ctx.env;
              if (env.apiPath) ctx.set('apiPath', env.apiPath);
              if (env.requestCtx) ctx.set('requestCtx', env.requestCtx);
              if (env.user) ctx.set('user', env.user);
              await next();
            });

            const appBasePath = `/apps/${appInfo.manifest?.name || appInfo.id}`;

            if (processedApp.routes && processedApp.routes.length > 0) {
              for (const route of processedApp.routes) {
                const isPrefix = route.path.startsWith(appBasePath) &&
                  (route.path.length === appBasePath.length || route.path[appBasePath.length] === '/');

                const fullPath = isPrefix
                  ? route.path
                  : `${appBasePath}${route.path.startsWith('/') ? '' : '/'}${route.path}`;

                const handler = route.handler;
                const method = route.method.toUpperCase();

                if (['GET', 'POST', 'PUT', 'PATCH', 'DELETE', 'OPTIONS', 'HEAD'].includes(method)) {
                  subApp.on(method, fullPath, handler as any);
                } else {
                  subApp.all(fullPath, handler as any);
                }
              }

              logger.debug(`鉁?Registered ${processedApp.routes.length} routes for app ${appInfo.manifest?.name || appInfo.id}`, {
                appBasePath,
                routesCount: processedApp.routes.length,
              });
            }

            processedAppsCache.set(appId, subApp);
            logger.info(`鉁?App cached: ${appId}`);
          } catch (error) {
            logger.error(`Failed to load app: ${appId}`, { error });
            throw error;
          }
        }

        try {
          const isWebSocket = c.req.header('upgrade')?.toLowerCase() === 'websocket';
          const requestObj = isWebSocket ? c.req.raw : c.req.raw.clone();

          const requestCtx = await createRequestCtx(
            appInfo,
            requestObj,
            c.req.method,
            apiPath,
            user,
            '/apps/:name/*'
          );

          // 瀵逛簬 WebSocket 璇锋眰锛屼笉瑕佸厠闅嗭紝鐩存帴浣跨敤鍘熷璇锋眰
          // 鍚﹀垯浼氬鑷?ReadableStream 琚攣瀹氾紝褰卞搷 upgradeWebSocket
          const fetchReq = isWebSocket ? c.req.raw : c.req.raw.clone();
          
          return await subApp.fetch(fetchReq, {
            apiPath,
            requestCtx,
            user
          });
        } catch (error) {
          if (error instanceof Error) {
            return errorHandler.handleError(error, appInfo);
          }
          return errorHandler.handleError(new Error(String(error)), appInfo);
        }
      },
      clearCache: (appId?: string) => {
        moduleLoader.clearCache(appId);
        if (appId) {
          processedAppsCache.delete(appId);
        } else {
          processedAppsCache.clear();
        }
      },
    };
  }

  return appHttpHandler;
}

export function registerAppRoutes(app: Hono, runtimeManager: Manager): void {
  managerInstance = runtimeManager;

  logger.info('馃摫 Initializing app routes...');

  app.get('/apps/:name', (c: Context) => {
    return c.redirect(`${c.req.path}/`);
  });

  app.get('/apps/:name/*', async (c: Context, next: Next) => {
    const { name } = c.req.param();
    const appsPath = join(Deno.cwd(), config.paths.apps);
    const tempPath = join(Deno.cwd(), config.paths.temp);
    const cachePath = join(Deno.cwd(), config.paths.cache);

    const appInfo = await getOrInstallApp(name, appsPath, tempPath, cachePath, c);

    if (!appInfo) {
      try {
        const templatePath = join(Deno.cwd(), 'resources', 'templates', '404.html');
        const html = await Deno.readTextFile(templatePath);
        return new Response(html, {
          status: 404,
          headers: { 'Content-Type': 'text/html; charset=utf-8' },
        });
      } catch {
        return c.json({ error: 'Not Found' }, 404);
      }
    }

    const identifierInPath = extractIdentifier(c.req.url);
    const staticPath = extractStatic(c.req.path, identifierInPath);

    if (
      staticPath.startsWith('/api/') || staticPath.startsWith('/sdk/') ||
      staticPath.startsWith('/proxy/') || staticPath.startsWith('/ws/') ||
      staticPath.startsWith('/sse/') || staticPath.startsWith('/events/')
    ) {
      return next();
    }

    let filePath = `${appInfo.path}${staticPath}`;

    try {
      if (!(await exists(filePath))) {
        filePath = `${appInfo.path}/index.html`;
      }

      const file = await Deno.readFile(filePath);
      const ext = filePath.split('.').pop();

      const contentType: Record<string, string> = {
        'html': 'text/html; charset=utf-8',
        'css': 'text/css',
        'js': 'application/javascript',
        'json': 'application/json',
        'png': 'image/png',
        'jpg': 'image/jpeg',
        'svg': 'image/svg+xml',
      };

      return new Response(file, {
        headers: {
          'Content-Type': contentType[ext || 'html'] || 'text/plain',
        },
      });
    } catch (error) {
      const err = toError(error);
      logger.warn(`File not found: ${staticPath}`, {
        ...getAppLogMeta(appInfo),
        error: err.message,
        path: staticPath,
      });
      return c.json({ error: 'File not found', path: staticPath }, 404);
    }
  });

  app.all('/apps/:name/*', async (c: Context) => {
    const { name } = c.req.param();
    const appsPath = join(Deno.cwd(), config.paths.apps);
    const tempPath = join(Deno.cwd(), config.paths.temp);
    const cachePath = join(Deno.cwd(), config.paths.cache);

    const appInfo = await getOrInstallApp(name, appsPath, tempPath, cachePath, c);

    if (!appInfo) {
      try {
        const templatePath = join(Deno.cwd(), 'resources', 'templates', '404.html');
        const html = await Deno.readTextFile(templatePath);
        return new Response(html, {
          status: 404,
          headers: { 'Content-Type': 'text/html; charset=utf-8' },
        });
      } catch {
        return c.json({ error: 'Not Found' }, 404);
      }
    }

    if (!appInfo.manifest?.hasBackend) {
      return c.json({ error: 'This app has no backend' }, 404);
    }

    const identifierInPath = extractIdentifier(c.req.url);
    const apiPath = extractApi(c.req.path, identifierInPath);


    const handler = getAppHttpHandler();
    return await handler.handleRequest(c, appInfo, apiPath);
  });

  logger.info('鉁?App routes registered (Hono Native)');
}

