let publicKey: CryptoKey | null = null;

/**
 * Initialize public key for token verification
 */
async function initTokenVerification(): Promise<void> {
  if (!publicKey) {
    publicKey = await importSPKI(TOKEN_CONFIG.PUBLIC_KEY, "EdDSA") as unknown as CryptoKey;
