 */
async function verifyToken(token: string): Promise<JWTPayload | null> {
  try {
    await initTokenVerification();
    const { payload } = await jwtVerify(token, publicKey!, {
      algorithms: ["EdDSA"]
    });
    return payload;
  } catch (error) {
    const err = error as Error;
    logger.debug('Token verification failed', { error: err.message });
    return null;
  }
}

// Authentication Middleware

const userCache = new Map<string, { user: User; timestamp: number }>();
const CACHE_TTL = 3600 * 1000;

const appCache = new Map<string, { appInfo: AppInfo; timestamp: number }>();
const APP_CACHE_TTL = 300 * 1000;

/**
 * Extract application ID from request URL path
 *
 * Extracts application ID from URL path in format `/apps/:id/*`.
 *
 * @param {Context} c - Hono context object
 * @returns {string|null} Application ID, or null if not found
 */
function extractAppId(c: Context): string | null {
  const urlPath = c.req.path;
  const pathMatch = urlPath.match(/^\/apps\/([^\/]+)/);
  if (pathMatch) {
    return pathMatch[1];
  }

  return null;
}

/**
 * Load application information (includes manifest and permissions)
 *
 * Loads application information from KV storage, caches for 5 minutes to improve performance.
 *
 * @param {string} appName - Application name (extracted from URL path)
 * @param {Function} getAppByName - Function to get app by name
 * @returns {Promise<Object|null>} Application info object (includes manifest and permissions), or null if not found
 */
async function loadAppInfo(
  appName: string,
  getAppByName: (name: string) => Promise<AppInfo | null>,
): Promise<AppInfo | null> {
  if (!appName) {
    return null;
  }

  const cached = appCache.get(appName);
  if (cached && Date.now() - cached.timestamp < APP_CACHE_TTL) {
    return cached.appInfo;
  }

  try {
    const appInfo = await getAppByName(appName);

    if (appInfo) {
      appCache.set(appName, {
        appInfo,
        timestamp: Date.now(),
      });

      logger.debug('App info loaded', {
        appName,
        appId: appInfo.manifest?.id,
        hasPermissions: !!appInfo.permissions,
      });
    }

    return appInfo;
  } catch (error) {
    const err = error as Error;
    logger.error('Failed to load app info', { appName, error: err.message });
    return null;
  }
}

