 *
 * Calls MSPBots API to verify user token, caches verification result for 1 hour.
 *
 * @param {string} token - Access token
 * @returns {Promise<Object|null>} User information object, or null if token is invalid
 */
async function verifyMspbotsToken(token: string): Promise<User | null> {
  const cached = userCache.get(token);
  if (cached && Date.now() - cached.timestamp < CACHE_TTL) {
    return cached.user;
  }

  try {
    const headers: Record<string, string> = {
      'Authorization': `Bearer ${token}`,
    };

    if (config.mspbots.token) {
      headers['X-Platform-Token'] = config.mspbots.token;
    }

    const response = await fetch(`${config.mspbots.apiUrl}/auth/verify`, {
      headers,
    });

    if (!response.ok) {
      return null;
    }

    const user = await response.json();

    userCache.set(token, {
      user,
      timestamp: Date.now(),
    });

    return user;
  } catch (error) {
    const err = error as Error;
    logger.error('Token verification failed', { error: err.message });
    return null;
  }
}

/**
 * Get Cookie value with specified name from request headers
 *
 * @param {Headers} headers - HTTP request headers object
 * @param {string} name - Cookie name
 * @returns {string|null} Cookie value, or null if not found
 */
function getCookie(headers: Headers, name: string): string | null {
  const cookie = headers.get('cookie');
  if (!cookie) return null;

  const match = cookie.match(new RegExp(`(^| )${name}=([^;]+)`));
  return match ? match[2] : null;
}

const staticResourcePattern = /\/apps\/[^/]+\/(assets|static|public)\/.*\.(js|css|png|jpg|jpeg|gif|svg|ico|woff|woff2|ttf|eot|mp4|webm|ogg|mp3|wav|flac|aac)$/;
const loginPathPattern = /\/apps\/mb-platform-user\/(login|callback|api\/auth\/providers\/enabled)/;


/**
 * Check if the host matches any of the allowed patterns
 * 
 * @param {string} host - Request host
 * @param {string[]} patterns - List of allowed domain patterns
 * @returns {boolean} True if host matches any pattern
 */
function isDomainMatch(host: string, patterns: string[]): boolean {
  if (!host || !patterns || patterns.length === 0) return false;
  
  return patterns.some(pattern => {
    if (pattern === host) return true;
    if (pattern.startsWith('*.')) {
      const domain = pattern.slice(2);
      return host.endsWith(domain) && (host.length === domain.length || host[host.length - domain.length - 1] === '.');
    }
    return false;
  });
}

