export async function authMiddleware(
  c: Context,
  next: Next,
  getAppByName: (name: string) => Promise<AppInfo | null>,
): Promise<Response | void> {
  logger.info('Auth middleware start', { path: c.req.path, method: c.req.method });
  //skip login
  if (staticResourcePattern.test(c.req.path)) {
    return next();
