      const authDomains = appInfo.manifest?.permissions?.auth;
      if (Array.isArray(authDomains)) {
        // Rule 1: "auth": [] -> All Public (No Auth Required)
        if (authDomains.length === 0) {
           logger.debug('Skipping auth: permissions.auth is empty [] (Public)');
           return next();
        }

        // Rule 2: "auth": ["*"] -> All Private (Auth Required)
        // If it contains "*", we enforce auth for all domains.
        if (authDomains.includes('*')) {
           logger.debug('Enforcing auth: permissions.auth contains "*"');
