/**
 * Error handling middleware
 *
 * Catches and logs all request errors, returns different error responses based on runtime environment:
 * - Development environment: Returns detailed error information and stack trace
 * - Production environment: Returns generic error information
 *
 * @param {Error} err - Error object
 * @param {Context} c - Hono context object
 * @returns {Response} HTTP error response (500 status code)
 */
export function errorMiddleware(err: Error, c: Context): Response {
  logger.error('Request error', {
    error: err.message,
    stack: err.stack,
    path: c.req.path,
    method: c.req.method,
  });

  if (config.isDev) {
    return c.json({
      error: err.message,
      stack: err.stack,
      path: c.req.path,
    }, 500);
  }

  return c.json({
    error: 'Internal Server Error',
  }, 500);
}

