   *
   * @param {string} registryUrl - Registry URL
   */
  constructor(registryUrl: string) {
    this.registryUrl = registryUrl;
  }

  /**
   * Get full package metadata
   *
   * @param {string} packageName - Package name, supports scoped packages (e.g. @mbaiapp/ai-chat)
   * @returns {Promise<PackageMetadata>} Complete package metadata object
   * @throws {Error} If the package does not exist or the request fails
   */
  async getPackageMetadata(packageName: string): Promise<PackageMetadata> {
    try {
      const encodedName = encodeURIComponent(packageName);
      const url = `${this.registryUrl}/${encodedName}`;

      logger.debug(`Fetching package metadata: ${url}`);

      const authorization = await resolveNpmAuthorizationHeader(url);
      const headers: Record<string, string> = {
        'Accept': 'application/json',
      };
      if (authorization) {
        headers['Authorization'] = authorization;
      }

      const response = await fetch(url, {
        headers,
      });

      if (!response.ok) {
        if (response.status === 404) {
          throw new Error(`Package "${packageName}" not found in registry`);
        }
        throw new Error(
          `Failed to fetch package metadata: ${response.status} ${response.statusText}`,
        );
      }

      const metadata = await response.json();
      return metadata as PackageMetadata;
    } catch (error: any) {
      logger.error(`Failed to get package metadata for ${packageName}`, {
        error: error.message,
      });
      throw error;
    }
  }

  /**
   * Get information for a specific package version
   *
   * Resolves the version (supports the 'latest' tag) and returns version
   * details and tarball URL.
   *
   * @param {string} packageName - Package name
   * @param {string} version - Version, supports 'latest' or an explicit version like '1.0.0'
   * @returns {Promise<PackageVersion & { tarball: string }>} Version information object
   * @throws {Error} If the version does not exist or the package has no 'latest' tag
   */
  async getPackageVersion(packageName: string, version = 'latest'): Promise<{
    name: string;
    version: string;
    dist: PackageDist;
    tarball: string;
  }> {
    try {
      const metadata = await this.getPackageMetadata(packageName);

      let actualVersion: string;
      if (version === 'latest') {
        actualVersion = metadata['dist-tags']?.latest;
        if (!actualVersion) {
          throw new Error(`Package "${packageName}" has no "latest" tag`);
        }
      } else {
        actualVersion = version;
      }

      const versionInfo = metadata.versions?.[actualVersion];
      if (!versionInfo) {
        throw new Error(`Version "${actualVersion}" not found for package "${packageName}"`);
      }

      logger.debug(`Resolved ${packageName}@${version} to ${actualVersion}`);

      return {
        name: packageName,
        version: actualVersion,
        dist: versionInfo.dist,
        tarball: versionInfo.dist?.tarball,
      };
    } catch (error: any) {
      logger.error(`Failed to get version info for ${packageName}@${version}`, {
        error: error.message,
      });
      throw error;
    }
  }

  /**
   * Download tarball file to the specified path
   *
   * @param {string} tarballUrl - Tarball download URL
   * @param {string} destPath - Destination file path
   * @returns {Promise<void>}
   * @throws {Error} If the download fails
   */
  async downloadTarball(tarballUrl: string, destPath: string): Promise<void> {
    try {
      logger.debug(`Downloading tarball: ${tarballUrl}`);

      const authorization = await resolveNpmAuthorizationHeader(tarballUrl);
      const response = await fetch(tarballUrl, {
        headers: authorization ? { Authorization: authorization } : undefined,
      });

      if (!response.ok) {
        throw new Error(`Failed to download tarball: ${response.status} ${response.statusText}`);
      }

      const arrayBuffer = await response.arrayBuffer();
      const data = new Uint8Array(arrayBuffer);

      await Deno.writeFile(destPath, data);

      logger.debug(`Tarball downloaded to: ${destPath}`);
    } catch (error: any) {
      logger.error(`Failed to download tarball from ${tarballUrl}`, {
        error: error.message,
      });
      throw error;
    }
  }
}

// NPM Loader

/**
 * NPM application loader class
 *
 * Provides functionality to fetch, extract and validate application packages
 * from the NPM Registry.
 */
export class NPMLoader {
  registry: NPMRegistry;

  /**
   * Create an NPM loader instance
   *
   * @param {string} registryUrl - NPM Registry URL
   */
  constructor(registryUrl: string) {
    this.registry = new NPMRegistry(registryUrl);
  }

  /**
   * Fetch an NPM package
   *
   * Downloads, extracts and validates an NPM package, and returns package
   * information and temporary directory paths. The caller is responsible for
   * calling cleanup to remove temporary files.
   *
   * @param {string} packageName - Package name
   * @param {string} version - Version
   * @param {string} tempPath - Temporary directory base path
   * @param {string} cachePath - Cache directory path
   * @returns {Promise<Object>} Package information object
   * @throws {Error} If fetching or validation fails
   */
  async fetchPackage(
    packageName: string,
    version: string,
    tempPath: string,
    cachePath: string,
  ): Promise<{
    packageName: string;
    version: string;
    manifest: AppManifest;
    tempDir: string;
    packageDir: string;
    tarballPath: string;
  }> {
    const tempId = crypto.randomUUID();
    const tempDir = join(tempPath, tempId);
    let tarballPath = '';

    try {
      logger.info(`Fetching package ${packageName}@${version}`);

      const versionInfo = await this.registry.getPackageVersion(packageName, version);

      if (!versionInfo.tarball) {
        throw new Error(`No tarball URL found for ${packageName}@${version}`);
      }

      await Deno.mkdir(cachePath, { recursive: true });

      const tarballName = `${packageName.replace(/[@\/]/g, '-')}-${versionInfo.version}.tgz`;
      tarballPath = join(cachePath, tarballName);

      await this.registry.downloadTarball(versionInfo.tarball, tarballPath);

      await Deno.mkdir(tempPath, { recursive: true });
      await Deno.mkdir(tempDir, { recursive: true });
      await this.extractTarball(tarballPath, tempDir);

      const packageDir = join(tempDir, 'package');
      const manifestPath = join(packageDir, 'manifest.json');

      let manifest: AppManifest;
      try {
        const manifestText = await Deno.readTextFile(manifestPath);
        manifest = JSON.parse(manifestText);
      } catch (error: any) {
        throw new Error(`Invalid or missing manifest.json: ${error.message}`);
      }

      if (!manifest.id || !manifest.name) {
        throw new Error('manifest.json must contain "id" and "name" fields');
      }

      logger.info(`Package ${packageName}@${versionInfo.version} fetched successfully`);

      return {
        packageName,
        version: versionInfo.version,
        manifest,
        tempDir,
        packageDir,
        tarballPath,
      };
    } catch (error: any) {
      await this.cleanup(tempDir, tarballPath);
      logger.error(`Failed to fetch package ${packageName}@${version}`, {
        error: error.message,
      });
      throw error;
    }
  }

  /**
   * Extract tarball file
   *
   * Uses the tar command to extract a .tgz file into the target directory.
   *
   * @param {string} tarballPath - Tarball file path
   * @param {string} targetDir - Target directory path
   * @returns {Promise<void>}
   * @throws {Error} If extraction fails
   */
  async extractTarball(tarballPath: string, targetDir: string): Promise<void> {
    try {
      logger.debug(`Extracting tarball: ${tarballPath} to ${targetDir}`);

      const process = new Deno.Command('tar', {
        args: ['-xzf', tarballPath, '-C', targetDir],
        stdout: 'piped',
        stderr: 'piped',
      });

      const { code, stderr } = await process.output();

      if (code !== 0) {
        const errorText = new TextDecoder().decode(stderr);
        throw new Error(`tar extraction failed: ${errorText}`);
      }

      logger.debug(`Tarball extracted successfully`);
    } catch (error: any) {
      logger.error(`Failed to extract tarball`, { error: error.message });
      throw error;
    }
  }

  /**
   * Clean up temporary files and directories
   *
   * Deletes the temporary directory and tarball file. Cleanup failures do not
   * throw errors; they are only logged as warnings.
   *
   * @param {string} tempDir - Temporary directory path
   * @param {string} tarballPath - Tarball file path
   * @returns {Promise<void>}
   */
  async cleanup(tempDir?: string, tarballPath?: string): Promise<void> {
    if (tempDir) {
      try {
        await Deno.remove(tempDir, { recursive: true });
        logger.debug(`Cleaned up temp directory: ${tempDir}`);
      } catch (error: any) {
        logger.warn(`Failed to cleanup temp directory: ${tempDir}`, {
          error: error.message,
        });
      }
    }

    if (tarballPath) {
      try {
        await Deno.remove(tarballPath);
        logger.debug(`Cleaned up tarball: ${tarballPath}`);
      } catch (error: any) {
        logger.warn(`Failed to cleanup tarball: ${tarballPath}`, {
          error: error.message,
        });
      }
    }
  }
}

// Application Service

/**
 * Recursively copy all files in a directory
 *
 * @param {string} srcDir - Source directory path
 * @param {string} destDir - Destination directory path
 * @throws {Error} If copying fails
 */
async function copyFiles(srcDir: string, destDir: string): Promise<void> {
  try {
    for await (const entry of Deno.readDir(srcDir)) {
      const srcPath = join(srcDir, entry.name);
      const destPath = join(destDir, entry.name);

      if (entry.isFile) {
        await Deno.copyFile(srcPath, destPath);
      } else if (entry.isDirectory) {
        await Deno.mkdir(destPath, { recursive: true });
        await copyFiles(srcPath, destPath);
      }
    }
  } catch (error: any) {
    logger.error(`Failed to copy files from ${srcDir} to ${destDir}`, {
      error: error.message,
    });
    throw error;
  }
}

/**
 * Clear all KV data for the specified application
 *
 * @param {string} appId - Application identifier
 * @param {Deno.Kv} kv - KV instance
 */
async function clearAppKVData(appId: string, kv: Deno.Kv): Promise<void> {
  try {
    const iter = kv.list({ prefix: ['apps', appId, 'kv'] });
    const deletes: Promise<void>[] = [];
    for await (const entry of iter) {
      deletes.push(kv.delete(entry.key));
    }
    await Promise.all(deletes);
    logger.info(`Cleared KV data for app: ${appId}`);
  } catch (error: any) {
    logger.error(`Failed to clear KV data for app: ${appId}`, {
      error: error.message,
    });
  }
}

/**
 * List all installed applications
 *
 * Reads the application list from the file system registry and supports search and pagination.
 *
 * @param {string} appsPath - Apps directory path
 * @param {Object} options - Query options
 * @returns {Promise<Object>} Application list and pagination info
 */
export async function listApps(
  appsPath: string,
  options: { page?: number; limit?: number; search?: string } = {},
): Promise<{
  apps: (AppRegistryInfo & { path: string })[];
  total: number;
  page: number;
  limit: number;
}> {
  const { page = 1, limit = 20, search = '' } = options;

  const allApps: (AppRegistryInfo & { path: string })[] = [];

  try {
    const registryApps = await listAppsFromRegistry();

    for (const appInfo of registryApps) {
      allApps.push({
        id: appInfo.id,
        dirName: appInfo.dirName,
        name: appInfo.manifest?.name, // Compatible with frontend usage
        manifest: appInfo.manifest,
        path: join(appsPath, appInfo.id),
        version: appInfo.version,
        source: appInfo.source,
        packageName: appInfo.packageName,
        installTime: appInfo.installTime,
        updateTime: appInfo.updateTime,
        status: appInfo.status,
      } as any); // Temporary cast to match frontend expectations if they differ
    }

    logger.debug(`Loaded ${allApps.length} apps from file system registry`);
  } catch (error: any) {
    logger.error('Failed to load apps from registry', { error: error.message });
  }

  let filteredApps = allApps;
  if (search) {
    const searchLower = search.toLowerCase();
    filteredApps = allApps.filter((app) =>
      app.id.toLowerCase().includes(searchLower) ||
      (app.manifest.name || '').toLowerCase().includes(searchLower)
    );
  }

  const total = filteredApps.length;
  const startIndex = (page - 1) * limit;
  const endIndex = startIndex + limit;
  const paginatedApps = filteredApps.slice(startIndex, endIndex);

  return {
    apps: paginatedApps,
    total,
    page,
    limit,
  };
}

/**
 * Get application details
 *
 * Reads full application information from the file system registry, including manifest and metadata.
 *
 * @param {string} appId - Application identifier
 * @param {string} appsPath - Apps directory path
 * @returns {Promise<Object|null>} Application info object, or null if not found
 */
export async function getApp(
  appId: string,
  appsPath: string,
): Promise<(AppRegistryInfo & { path: string }) | null> {
  const appInfo = await getAppFromRegistry(appId);

  if (!appInfo) {
    return null;
  }

  return {
    ...appInfo,
    id: appInfo.id || appId,
    path: join(appsPath, appInfo.id || appId),
  };
}

/**
 * Find application by name
 *
 * Iterates all applications and finds the one whose name matches.
 *
 * @param {string} appName - Application name (URL-encoded)
 * @param {string} appsPath - Apps directory path
 * @returns {Promise<Object|null>} Application info object, or null if not found
 */

async function findAppDirectory(
  appsPath: string,
  possibleDirs: string[],
): Promise<string | null> {
  for (const dirName of possibleDirs) {
    if (!dirName) continue;
    const testPath = join(appsPath, dirName);
    try {
      const stat = await Deno.stat(testPath);
      if (stat.isDirectory) {
        return testPath;
      }
    } catch {
      continue;
    }
  }
  return null;
}

export async function getAppByName(
  appName: string,
  appsPath: string,
): Promise<(AppRegistryInfo & { path: string }) | null> {
  const decodedName = decodeURIComponent(appName);

  try {
    // First try to get app directly from registry by name
    const directAppInfo = await getAppFromRegistry(decodedName);
    if (directAppInfo) {
      const appId = directAppInfo.id;
      if (!appId) {
        logger.warn('App found but missing id field', { appName: decodedName });
      } else {
        let appPath = null;
        if (directAppInfo.dirName) {
          appPath = join(appsPath, directAppInfo.dirName);
        } else {
          const possibleDirs = [
            decodedName,
            directAppInfo.manifest?.id,
            appId,
          ];

          appPath = await findAppDirectory(appsPath, possibleDirs) || join(appsPath, decodedName);
        }

        return {
          ...directAppInfo,
          id: appId,
          path: appPath,
        };
      }
    }

    // If direct lookup fails, try to find app by manifest name
    const registryApps = await listAppsFromRegistry();

    for (const appInfo of registryApps) {
      if (appInfo.manifest?.name === decodedName) {
        const appId = appInfo.id;
        if (!appId) {
          logger.warn('App found but missing id field', { appName: decodedName });
          continue;
        }

        let appPath = null;
        if (appInfo.dirName) {
          appPath = join(appsPath, appInfo.dirName);
        } else {
          const possibleDirs = [
            decodedName,
            appInfo.manifest?.id,
            appId,
          ];

          appPath = await findAppDirectory(appsPath, possibleDirs) || join(appsPath, decodedName);
        }

        return {
          ...appInfo,
          id: appId,
          path: appPath,
        };
      }
    }

    // If still not found, try to find app by directory name
    try {
      const appDir = join(appsPath, decodedName);
      const stat = await Deno.stat(appDir);
      if (stat.isDirectory) {
        // Check if there's a manifest.json file in the directory
        const manifestPath = join(appDir, 'manifest.json');
        try {
          const manifestText = await Deno.readTextFile(manifestPath);
          const manifest = JSON.parse(manifestText);
          
          if (manifest.id && manifest.name) {
            // Create app info from manifest
            const appInfo: AppRegistryInfo = {
              id: manifest.id,
              dirName: decodedName,
              packageName: null,
              version: manifest.version || '0.0.0',
              installTime: new Date().toISOString(),
              updateTime: new Date().toISOString(),
              source: 'local',
              status: 'running',
              manifest,
            };
            
            // Save app info to registry
            await saveAppToRegistry(decodedName, appInfo);
            
            return {
              ...appInfo,
              path: appDir,
            };
          }
        } catch {
          // No manifest.json file, continue
        }
      }
    } catch {
      // App directory doesn't exist, continue
    }
  } catch (error: any) {
    logger.error('Failed to find app by name', { appName: decodedName, error: error.message });
  }

  return null;
}

/**
 * Install application from NPM Registry
 *
 * Downloads, extracts, validates and installs the application from an NPM package.
 *
 * @param {string} packageName - NPM package name
 * @param {string} version - Version
 * @param {NPMLoader} npmLoader - NPM loader instance
 * @param {Deno.Kv} kv - KV instance
 * @param {string} appsPath - Apps directory path
 * @param {string} tempPath - Temporary directory path
 * @param {string} cachePath - Cache directory path
 * @param {Function} clearModuleCache - Function to clear module cache
 * @returns {Promise<Object>} Installation result
 * @throws {Error} If installation fails
 */
export async function installFromNPM(
  packageName: string,
  version: string,
  appsPath: string,
  tempPath: string,
  cachePath: string,
  clearModuleCache: (appId?: string) => Promise<void> | void,
): Promise<{ appId: string; version: string; packageName: string; permissions?: Permission[] }> {
  const npmLoader = new NPMLoader(config.npm.registryUrl);
  let tempDir: string | undefined = undefined;
  let tarballPath: string | undefined = undefined;

  try {
    logger.info(`Installing app from npm: ${packageName}@${version}`);

    const pkg = await npmLoader.fetchPackage(packageName, version, tempPath, cachePath);
    tempDir = pkg.tempDir;
    tarballPath = pkg.tarballPath;

    const { id: appId, name: appName } = pkg.manifest;
    
    const permissions = await parseHttpJson(pkg.packageDir, appId);
    
    if (permissions.length > 0) {
      await submitPermissions(appId, permissions);
    }

    const appDir = join(appsPath, appName);

    try {
      const existing = await Deno.stat(appDir);

      if (existing.isDirectory) {
        logger.info(`App ${appName} already exists, will be replaced`);
        try {
          await Deno.remove(appDir, { recursive: true });
        } catch (error: any) {
          logger.warn(`Failed to remove existing app directory`, { error: error.message });
        }
      }
    } catch {
      // Directory doesn't exist, continue
    }

    await Deno.mkdir(appDir, { recursive: true });
    await copyFiles(pkg.packageDir, appDir);

    // Check if app already exists
    const existingApp = await getAppFromRegistry(appName);
    
    const appInfo: AppRegistryInfo = {
      id: appId,
      dirName: appName,
      packageName,
      version: pkg.version,
      installTime: existingApp ? existingApp.installTime : new Date().toISOString(),
      updateTime: new Date().toISOString(),
      source: 'npm',
      status: 'running',
      manifest: pkg.manifest,
    };

    // Save app info to file system registry
    await saveAppToRegistry(appName, appInfo);

    await clearModuleCache(appId);

    logger.info(`App ${appId} installed successfully from ${packageName}@${pkg.version}`);

    return { appId, version: pkg.version, packageName, permissions };
  } finally {
    if (tempDir || tarballPath) {
      await npmLoader.cleanup(tempDir, tarballPath);
    }
  }
}

/**
 * Update NPM application to new version
 *
 * @param {string} appName - Application name
 * @param {string} version - Target version
 * @param {NPMLoader} npmLoader - NPM loader instance
 * @param {string} appsPath - Apps directory path
 * @param {string} tempPath - Temporary directory path
 * @param {string} cachePath - Cache directory path
 * @param {Function} clearModuleCache - Function to clear module cache
 * @returns {Promise<Object>} Update result
 * @throws {Error} If app not found or not from npm
 */
export async function updateFromNPM(
  appName: string,
  version: string,
  appsPath: string,
  tempPath: string,
  cachePath: string,
  clearModuleCache: (appId?: string) => Promise<void> | void,
): Promise<{ appId: string; version: string; packageName: string; permissions?: Permission[] }> {
  const npmLoader = new NPMLoader(config.npm.registryUrl);
  logger.info(`Updating app: ${appName} to version ${version}`);

  const appInfo = await getAppFromRegistry(appName);

  if (!appInfo || !appInfo.packageName) {
    throw new Error(`App ${appName} not found or not from npm`);
  }

  return await installFromNPM(
    appInfo.packageName,
    version,
    appsPath,
    tempPath,
    cachePath,
    clearModuleCache,
  );
}

/**
 * Delete application
 *
 * Supports deleting local and NPM applications.
 *
 * @param {string} appName - Application name
 * @param {string} appsPath - Apps directory path
 * @param {Function} clearModuleCache - Function to clear module cache
 * @param {Object} options - Delete options
 * @returns {Promise<Object>} Delete result
 * @throws {Error} If app not found
 */
export async function deleteApp(
  appName: string,
  appsPath: string,
  clearModuleCache: (appId?: string) => Promise<void> | void,
  options: { cleanupKV?: boolean } = {},
): Promise<{
  id: string;
  name: string;
  filesDeleted: number;
  kvCleaned: boolean;
}> {
  const { cleanupKV = false } = options;

  logger.info(`Deleting app: ${appName}`);

  const appInfo = await getAppFromRegistry(appName);

  if (!appInfo) {
    throw new Error(`APP_NOT_FOUND: App ${appName} not found`);
  }

  const dirName = appInfo.dirName || appInfo.manifest?.name || appInfo.id;
  const appPath = join(appsPath, dirName);

  let filesDeleted = 0;
  try {
    for await (const entry of Deno.readDir(appPath)) {
      if (entry.isFile) {
        filesDeleted++;
      }
    }
    await Deno.remove(appPath, { recursive: true });
  } catch (error: any) {
    logger.warn(`Failed to remove app directory: ${appPath}`, { error: error.message });
  }

  // Delete app from file system registry
  await deleteAppFromRegistry(appName);

  let kvCleaned = false;
  // KV cleanup is no longer needed since we're using file system storage

  const appId = appInfo.id || appInfo.manifest?.id;
  await clearModuleCache(appId);

  logger.info(`App ${appName} deleted successfully`, {
    appId: appInfo.id,
    filesDeleted,
    kvCleaned,
  });

  return {
    id: appInfo.id,
    name: appName,
    filesDeleted,
    kvCleaned,
  };
}

/**
 * Force resync from filesystem to registry
 *
 * Scans applications in the filesystem and syncs them to the file system registry.
 * Note: This will overwrite registry records with filesystem data.
 *
 * @param {string} appsPath - Apps directory path
 * @returns {Promise<Object>} Sync result
 * @throws {Error} If sync fails
 */
export async function saveAppToRegistry(appName: string, appInfo: any): Promise<void> {
  try {
    const filePath = await getRegistryFilePath(appName);
    await Deno.writeTextFile(filePath, JSON.stringify(appInfo, null, 2));
  } catch (error: any) {
    logger.error(`Failed to save app to registry: ${error.message}`, { appName });
    throw error;
  }
}

export async function forceResyncFromFiles(
  appsPath: string,
): Promise<{ syncCount: number }> {
  let syncCount = 0;

  try {
    logger.warn('鈿狅笍 FORCE RESYNC: Overwriting registry from filesystem...');

    try {
      await Deno.mkdir(appsPath, { recursive: true });
    } catch {
      // Directory already exists, ignore
    }

    for await (const entry of Deno.readDir(appsPath)) {
      if (!entry.isDirectory) continue;
      if (entry.name.startsWith('_')) continue;

      const dirName = entry.name;
      const manifestPath = join(appsPath, dirName, 'manifest.json');
      if (!await Deno.stat(manifestPath).catch(() => false)) continue;

      try {
        const manifestText = await Deno.readTextFile(manifestPath);
        const manifest = JSON.parse(manifestText) as AppManifest;

        if (!manifest.id || !manifest.name) {
          logger.warn(`Invalid manifest in ${dirName}`, { manifest });
          continue;
        }

        const appName = manifest.name;

        const appInfo: AppRegistryInfo = {
          id: manifest.id,
          dirName: dirName,
          packageName: null,
          version: manifest.version || '0.0.0',
          installTime: new Date().toISOString(),
          updateTime: new Date().toISOString(),
          source: 'local',
          status: 'running',
          manifest,
        };

        await saveAppToRegistry(appName, appInfo);

        syncCount++;
        logger.info(`Force synced: ${appName} (id: ${manifest.id}, from directory ${dirName})`);
