import  { Hono } from 'hono';
import type { Context } from 'hono';
import type { AppInfo, HandlerParams, Query, PathParams, User } from './types.ts';
import { logger } from '@packages/logger';

type LegacyHandler = (params: HandlerParams) => unknown | Promise<unknown>;
type LegacyRouteMap = Record<string, LegacyHandler>;

type HttpMethod = 'get' | 'post' | 'put' | 'patch' | 'delete' | 'head' | 'options' | 'all';

export interface RouteCompatOptions {
  appInfo: AppInfo;
  getUser: (c: Context) => User | undefined;
  getBody: (c: Context) => unknown | Promise<unknown>;
  getQuery: (c: Context) => Query;
  getParams: (c: Context) => PathParams;
}

export function convertLegacyRoutes(
  routeMap: LegacyRouteMap,
  options: RouteCompatOptions
): Hono {
  const app = new Hono();

  for (const [path, handler] of Object.entries(routeMap)) {
    const { method, routePath } = parseRoutePath(path);
    addRoute(app, method, routePath, handler, options);
  }

  return app;
}

function parseRoutePath(path: string): { method: HttpMethod; routePath: string } {
  const methodMatch = path.match(/^(GET|POST|PUT|PATCH|DELETE|HEAD|OPTIONS)\s+(.+)$/i);

  if (methodMatch) {
    const [, methodStr, routePath] = methodMatch;
    return {
      method: methodStr.toLowerCase() as HttpMethod,
      routePath: routePath.trim(),
    };
  }

  const allMethods: HttpMethod[] = ['get', 'post', 'put', 'patch', 'delete', 'head', 'options'];

  for (const m of allMethods) {
    const prefix = `${m.toUpperCase()} `;
    if (path.toUpperCase().startsWith(prefix)) {
      return {
        method: m,
        routePath: path.slice(prefix.length).trim(),
      };
    }
  }

  return {
    method: 'all',
    routePath: path,
  };
}

function addRoute(
  app: Hono,
  method: HttpMethod,
  path: string,
  handler: LegacyHandler,
  options: RouteCompatOptions
): void {
  const wrappedHandler = async (c: Context) => {
    const requestCtx = (c as any).var?.requestCtx;
    const routeParams = c.req.param();
    
    let params;
    if (requestCtx) {
      const appInfo = requestCtx.app || {};
      params = {
        id: appInfo.id || '',
        name: appInfo.name || '',
        version: appInfo.version || '1.0.0',
        description: appInfo.description || '',
        metadata: appInfo.metadata || {},
        headers: requestCtx.headers || {},
        body: requestCtx.body,
        query: requestCtx.query || {},
        params: { ...requestCtx.params, ...routeParams },
        method: requestCtx.method || c.req.method,
        pathname: requestCtx.pathname || c.req.path,
        requestUrl: requestCtx.requestUrl || c.req.url,
        user: requestCtx.user,
      };
    } else {
      params = await buildHandlerParams(c, options);
    }
    
    const result = await handler(params);
    return convertToResponse(result);
  };

  (wrappedHandler as any)._isLegacyRoute = true;

  switch (method) {
    case 'get':
      app.get(path, wrappedHandler);
      break;
    case 'post':
      app.post(path, wrappedHandler);
      break;
    case 'put':
      app.put(path, wrappedHandler);
      break;
    case 'patch':
      app.patch(path, wrappedHandler);
      break;
    case 'delete':
      app.delete(path, wrappedHandler);
      break;
    case 'head':
      (app as unknown as Record<string, (path: string, handler: unknown) => void>).head?.(path, wrappedHandler);
      break;
    case 'options':
      app.options(path, wrappedHandler);
      break;
    case 'all':
      app.all(path, wrappedHandler);
      break;
  }
}

async function buildHandlerParams(c: Context, options: RouteCompatOptions): HandlerParams {
  const { appInfo, getUser, getBody, getQuery, getParams } = options;
  const manifest = appInfo.manifest;

  logger.debug('buildHandlerParams: appInfo.id', { id: appInfo.id, name: manifest?.name });

  const user = getUser(c);
  const bodyResult = getBody(c);
  const body = bodyResult instanceof Promise ? await bodyResult : bodyResult;
  const query = getQuery(c);
  const params = getParams(c);

  logger.debug('buildHandlerParams: params', { 
    queryKeys: Object.keys(query || {}),
    paramsKeys: Object.keys(params || {}),
    body: body ? 'present' : 'empty',
    pathname: c.req.path
  });

  const effectiveUser = user || { id: 'anonymous', email: '', displayName: 'Guest', roles: [] };

  const headers: Record<string, string> = {};
  for (const [key, value] of c.req.raw.headers.entries()) {
    if (value !== undefined) {
      headers[key] = value;
    }
  }

  return {
    id: appInfo.id,
    name: manifest?.name || appInfo.id,
    version: manifest?.version || '1.0.0',
    description: manifest?.description || '',
    metadata: (manifest?.metadata as Record<string, unknown>) || {},
    headers,
    body,
    query,
    params,
    method: c.req.method,
    pathname: c.req.path,
    requestUrl: c.req.url,
    user: effectiveUser,
  };
}

export function convertToResponse(result: unknown): Response {
  if (result === undefined || result === null) {
    return new Response(null, { status: 204 });
  }

  if (result instanceof Response) {
    return result;
  }

  if (result instanceof Error) {
    return new Response(JSON.stringify({ error: result.message }), {
      status: 500,
      headers: { 'Content-Type': 'application/json' },
    });
  }

  if (typeof result === 'string' || result instanceof String) {
    return new Response(result.toString(), {
      status: 200,
      headers: { 'Content-Type': 'text/plain' },
    });
  }

  if (result instanceof Uint8Array || ArrayBuffer.isView(result)) {
    return new Response(result as BodyInit, {
      status: 200,
    });
  }

  const body = JSON.stringify(result);
  return new Response(body, {
    status: 200,
    headers: { 'Content-Type': 'application/json' },
  });
}

export function isHonoApp(module: unknown): module is Hono {
  if (!module || typeof module !== 'object') {
    return false;
  }

  const obj = module as Record<string, unknown>;
  return (
    typeof obj.get === 'function' &&
    typeof obj.post === 'function' &&
    typeof obj.put === 'function' &&
    typeof obj.delete === 'function' &&
    typeof obj.patch === 'function'
  );
}

export function isLegacyRouteMap(module: unknown): module is LegacyRouteMap {
  if (!module || typeof module !== 'object') {
    return false;
  }

  const obj = module as Record<string, unknown>;

  for (const value of Object.values(obj)) {
    if (typeof value !== 'function') {
      return false;
    }
  }

  return true;
}

export function isServerFunction(module: unknown): module is (app: Hono) => LegacyRouteMap {
  return typeof module === 'function';
}

export function detectModuleType(module: unknown): 'hono' | 'legacy' | 'function' | 'unknown' {
  if (isHonoApp(module)) {
    return 'hono';
  }

  if (isLegacyRouteMap(module)) {
    return 'legacy';
  }

  if (isServerFunction(module)) {
    return 'function';
  }

  return 'unknown';
}

export function processAppModule(
  module: unknown,
  options: RouteCompatOptions
): Hono {
  const type = detectModuleType(module);

  if (type === 'hono') {
    return module as Hono;
  }

  if (type === 'legacy') {
    return convertLegacyRoutes(module as LegacyRouteMap, options);
  }

  if (type === 'function') {
    const serverFn = module as (app: Hono) => LegacyRouteMap;
    const honoApp = new Hono();

    const routes = serverFn(honoApp);

    if (honoApp.routes && honoApp.routes.length > 0) {
      const legacyApp = routes && typeof routes === 'object'
        ? convertLegacyRoutes(routes as LegacyRouteMap, options)
        : new Hono();
      honoApp.route('/', legacyApp);
      return honoApp;
    }

    if (routes && typeof routes === 'object') {
      return convertLegacyRoutes(routes as LegacyRouteMap, options);
    }

    return honoApp;
  }

  throw new Error('Unknown module type: cannot convert to Hono app');
}

