export type RouteHandler<TParams extends HandlerParamsBase = HandlerParamsBase> = Handler<TParams>;

export type RouteMap<TParams extends HandlerParamsBase = HandlerParamsBase> = Record<
  string,
  RouteHandler<TParams>
>;

export function match<TParams extends HandlerParamsBase>(
  routes: RouteMap<TParams>,
  method: string,
  path: string,
): { handler: RouteHandler<TParams>; routePattern: string } | null {
  const directKey = `${method} ${path}`;
  if (routes[directKey]) {
    return { handler: routes[directKey], routePattern: path };
  }

  const candidates: string[] = [];
  if (!path.startsWith('/api')) {
    candidates.push(`/api${path}`);
  } else {
    candidates.push(path.substring(4) || '/');
  }
  candidates.push(path);

  const methodPrefix = `${method} `;
  for (const p of candidates) {
    for (const key in routes) {
      if (!key.startsWith(methodPrefix)) continue;
      const pattern = key.substring(method.length + 1);
      if (matchPattern(pattern, p)) {
        return { handler: routes[key], routePattern: pattern };
      }
    }
  }

  return null;
}

