  warn: (msg: string, meta?: Record<string, unknown>) => meta ? console.warn(`[WARN] ${msg}`, meta) : console.warn(`[WARN] ${msg}`),
  info: (msg: string, meta?: Record<string, unknown>) => meta ? console.log(`[INFO] ${msg}`, meta) : console.log(`[INFO] ${msg}`),
  debug: (msg: string, meta?: Record<string, unknown>) => meta ? console.log(`[DEBUG] ${msg}`, meta) : console.log(`[DEBUG] ${msg}`),
};

export function splitPathname(pathname: string): string[] {
  return pathname.split('/').filter((s) => s.length > 0);
}

export function decodeParam(value: string): string {
  try {
    return decodeURIComponent(value);
  } catch {
    return value;
  }
}

export function matchPattern(pattern: string, path: string): boolean {
  const patternParts = splitPathname(pattern);
  const pathParts = splitPathname(path);

  let pi = 0;
  let si = 0;

  while (pi < patternParts.length && si < pathParts.length) {
    const p = patternParts[pi];
    const s = pathParts[si];

    if (p === '*') {
      return true;
    }

    if (p.startsWith(':')) {
      pi++;
      si++;
      continue;
    }

    if (p !== s) {
      return false;
    }

    pi++;
    si++;
  }

  if (pi === patternParts.length && si === pathParts.length) {
    return true;
  }

  if (pi === patternParts.length - 1 && patternParts[pi] === '*') {
    return true;
  }

  return false;
}

export function parsePathParams(routePattern: string, actualPath: string): PathParams {
  const patternParts = splitPathname(routePattern);
  const pathParts = splitPathname(actualPath);

  const params: PathParams = {};

  let pi = 0;
  let si = 0;

  while (pi < patternParts.length && si < pathParts.length) {
    const p = patternParts[pi];
    const s = pathParts[si];

    if (p === '*') {
      break;
    }

    if (p.startsWith(':')) {
      const key = p.slice(1);
      if (key) {
        params[key] = decodeParam(s);
      }
      pi++;
      si++;
      continue;
    }

    if (p !== s) {
      return {};
    }

    pi++;
    si++;
  }

  if (pi === patternParts.length) {
    return params;
  }

  if (pi === patternParts.length - 1 && patternParts[pi] === '*') {
    return params;
  }

  return params;
}

