export class AppContextBuilder {
  async buildContext(
    appInfo: AppInfo,
    c: Context,
    apiPath: string,
    user?: User
  ): Promise<HandlerParams> {
    const manifest = appInfo.manifest;
    if (!manifest) {
      throw new Error(`Manifest not found for app: ${appInfo.id}`);
    }

    const params = this.extractPathParams(c);
    const query = this.extractQuery(c);
    const body = await this.extractBody(c);
    const headers = this.extractHeaders(c);

    return {
      id: appInfo.id,
      name: manifest.name || appInfo.id,
      version: manifest.version || '1.0.0',
      description: manifest.description || '',
      metadata: (manifest.metadata as Record<string, unknown>) || {},
      headers,
      body,
      query,
      params,
      method: c.req.method,
      pathname: apiPath,
      requestUrl: c.req.url,
      user,
    };
  }

  private extractPathParams(c: Context): PathParams {
    const params: PathParams = {};
    const routeParams = c.req.param();

    for (const [key, value] of Object.entries(routeParams)) {
      if (key !== '*') {
        params[key] = value;
      }
    }

    return params;
  }

  private extractQuery(c: Context): Query {
    const query: Query = {};
    const url = new URL(c.req.url);

    for (const [key, value] of url.searchParams.entries()) {
      const existing = query[key];
      if (existing !== undefined) {
        if (Array.isArray(existing)) {
          existing.push(value);
        } else {
          query[key] = [existing, value];
        }
      } else {
        query[key] = value;
      }
    }

    return query;
  }

  private async extractBody(c: Context): Promise<unknown> {
    const contentType = c.req.header('Content-Type') || c.req.header('content-type') || '';
    const isBinaryUpload = contentType.startsWith('application/octet-stream');
    
    if (isBinaryUpload) {
      return undefined;
    }
    
    return await c.req.parseBody().catch(() => ({}));
  }

  private extractHeaders(c: Context): Record<string, string> {
    const headers: Record<string, string> = {};
    const headerMap = c.req.raw.headers;

    for (const [key, value] of headerMap.entries()) {
      if (value !== undefined) {
        headers[key] = value;
      }
    }

    return headers;
  }

