  };

  const contentType = getHeader('Content-Type') || getHeader('content-type') || '';
  const upgradeHeader = getHeader('Upgrade') || getHeader('upgrade') || '';
  const isWebSocket = upgradeHeader.toLowerCase() === 'websocket';
  
  const isBinaryUpload = contentType.startsWith('application/octet-stream');
  const isMultipart = contentType.startsWith('multipart/form-data');
  const isJson = contentType.includes('application/json');
  const isUrlEncoded = contentType.includes('application/x-www-form-urlencoded');
  
  let parsedBody: unknown;
  
  if (isWebSocket) {
    parsedBody = undefined;
  } else if (isBinaryUpload) {
    parsedBody = undefined;
  } else if (isMultipart || isUrlEncoded) {
    if ('parseBody' in request && typeof (request as any).parseBody === 'function') {
      parsedBody = await (request as any).parseBody();
    } else {
      const formData = await (request as Request).formData();
      const body: Record<string, any> = {};
      formData.forEach((value, key) => {
